<?php use PreConselho\Support\{Csrf,PasswordPolicy};ob_start();?><section class="card narrow"><div class="login-intro"><span class="login-icon" aria-hidden="true">🔑</span><h1>Alterar minha senha</h1><p><?=!empty($_SESSION['user']['alterar_senha'])?'Por segurança, crie uma nova senha antes de continuar.':'Atualize sua senha de acesso ao sistema.'?></p></div><form method="post" action="/minha-senha"><input type="hidden" name="_csrf" value="<?=e(Csrf::token())?>"><label>Senha atual<input name="senha_atual" type="password" autocomplete="current-password" required></label><label>Nova senha<input name="nova_senha" type="password" minlength="<?=PasswordPolicy::MIN_LENGTH?>" autocomplete="new-password" required><small class="helper">Use pelo menos <?=PasswordPolicy::MIN_LENGTH?> caracteres.</small></label><label>Confirmar nova senha<input name="confirmar_senha" type="password" minlength="<?=PasswordPolicy::MIN_LENGTH?>" autocomplete="new-password" required></label><button class="login-submit">Salvar nova senha</button></form></section><?php $content=ob_get_clean();require __DIR__.'/layout.php';
